SELECT event_id, MAX(max_temp) AS max_temperature, MIN(min_temp) AS min_temperature
FROM temperature_records
GROUP BY event_id;

SELECT total_mm
FROM weather_events
ORDER BY total_mm DESC;

SELECT event_id, max_temp
FROM temperature_records
ORDER BY max_temp DESC;

SELECT dates
FROM weather_events
ORDER BY dates DESC;

SELECT event_id
FROM weather_events
ORDER BY event_id;
